                weight: weight * 0.9,
                signSource: signName,
                houseSource: 1,
                originType: .natal
            ))
            
        case 4: // IC - Private self and emotional foundation
            tokens.append(StyleToken(
                name: "foundational",
                type: "mood",
                weight: weight,
                signSource: signName,
                houseSource: 4,
                originType: .natal
            ))
            tokens.append(StyleToken(
                name: "comforting",
                type: "texture",
                weight: weight * 0.8,
                signSource: signName,
                houseSource: 4,
                originType: .natal
            ))
            
        case 7: // Descendant - Partnerships and social presentation
            tokens.append(StyleToken(
                name: "harmonious",
                type: "expression",
                weight: weight,
                signSource: signName,
                houseSource: 7,
                originType: .natal
            ))
            tokens.append(StyleToken(
                name: "balanced",
                type: "structure",
                weight: weight * 0.8,
                signSource: signName,
                houseSource: 7,
                originType: .natal
            ))
            
        case 10: // Midheaven - Public image and professional presentation
            tokens.append(StyleToken(
                name: "authoritative",
