                signSource: signName,
                houseSource: 10,
                originType: .natal
            ))
            tokens.append(StyleToken(
                name: "polished",
                type: "texture",
                weight: weight * 0.9,
                signSource: signName,
                houseSource: 10,
                originType: .natal
            ))
            
        default:
